## Plastic counts





::: {.cell}

```{.r .cell-code .hidden}
sampling <- tibble(
  start = ymd_hms(c(
    "2023-04-13 10:00:00",
    "2023-04-13 10:00:00",
    "2023-04-13 12:00:00",
    "2023-04-13 12:00:00",
    "2023-04-14 10:00:00",
    "2023-04-14 10:00:00",
    "2023-04-14 12:00:00",
    "2023-04-14 12:00:00"
  )),
  end = ymd_hms(c(
    "2023-04-13 11:45:00",
    "2023-04-13 11:30:00",
    "2023-04-13 13:30:00",
    "2023-04-13 12:45:00",
    "2023-04-14 11:45:00",
    "2023-04-14 11:45:00",
    "2023-04-14 13:45:00",
    "2023-04-14 13:45:00"
  )),
  watershed = c("East", "West", "East", "West", "East", "West", "East", "West"),
  count = c(3, 3, 2, 3, 1, 0, 1, 2),
  period = c(1, 1, 2, 2, 3, 3, 4, 4)
)

results <- discharge |>
  inner_join(
    sampling,
    join_by(watershed, date_time >= start, date_time <= end)
  ) |>
summarise(volume = sum(volume_m3), 
          count = max(count),
          .by = c(watershed, period)) |>
  summarise(volume = sum(volume), 
          count = sum(count),
          .by = c(watershed)) |>
  mutate(conc =  count/volume)
```
:::







## PC estimation






::: {#tbl-runoff .cell tbl-cap='Estimated total ploymer coating export from West and East watersheds, based on accumulated runoff volume and volume-weighted mean concentration.'}

```{.r .cell-code .hidden}
#| label: tbl-runoff
#| tbl-cap: Estimated total ploymer coating export from West and East watersheds, based on accumulated runoff volume and volume-weighted mean concentration.

estimate <- discharge |>
  summarise(total_Q = sum(volume_m3), .by = watershed) |>
  full_join(results) |>
  mutate(total = conc * total_Q) |>
  mutate(area = case_when(watershed == "West" ~ 5.15,
                          watershed == "East" ~ 4.16)) |>
  select(watershed, area, total_Q, conc, total)
```

